text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed_decisions": [
        {
          "item": "공개 릴리스 목표는 스모크 테스트 통과를 전제로 금요일 15:00 KST로 확정한다."
        },
        {
          "item": "packageName 불일치가 발생했을 때는 스크립트를 무시하지 않고, 우선 패키지 설정/계약을 확인한다."
        },
        {
          "item": "설정(contract) 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
        },
        {
          "item": "Minjun은 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다."
        },
        {
          "item": "Doyun은 금요일 12:00 KST까지 실패 트리아지 노트를 action_items.md에 작성한다."
        }
      ],
      "rejected_proposals": [
        {
          "item": "Hara가 제안한 'smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경' 제안은 회의에서 반려됨."
        }
      ],
      "internal_stretch_goals": [
        {
          "item": "수요일 릴리스 제안은 외부 공개 일정이 아닌 내부 스트레치 골로만 유지됨."
        }
      ]
    },
    "non_decisions": [
      {
        "item": "Hara가 Minjun의 스모크 결과 공유 후 tarball 경로를 확인하는 작업은 예정되어 있으나, 구체 기한은 미확정."
      },
      {
        "item": "Seoyeon이 제안한 README 설치 단계 리뷰는 목요일 가능 시 실행 목표이지만, 책임자(Owner) 미지정."
      },
      {
        "item": "README 리뷰 또는 tarball 확인의 최종 완료 조건은 이 회의록만으로는 확정되지 않음."
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있음."
      },
      {
        "item": "README 설치 단계가 최신 상태가 아니면 릴리스 노트가 사용자에게 오도될 수 있음."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 골(수요일 목표)을 기재할지 여부는 결정되지 않음."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 테스트 결과 공유 후 생성 tarball 경로 점검",
      "due": "미정(결과 공유 이후)",
      "status": "예정",
      "source_certainty": "중간"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계 최신성 검토",
      "due": "목요일 가능 시",
      "status": "보류",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00까지 Minjun의 스모크 테스트 결과를 확인하고 pass/fail 상태 및 로그를 확인한다.",
      "Doyun의 action_items.md 트리아지 노트 제출 여부 및 내용 반영 가능성을 점검한다.",
      "Hara의 tarball 경로 확인 결과를 수집해 릴리스 종결 조건과 연결한다.",
      "Seoyeon의 README 리뷰 제안이 실행되었는지와 실제 반영 대상 항목이 있는지 확인한다.",
      "최종 릴리스 승인 권한자 지정 및 릴리스 노트 메시지 범위(수요일 스트레치 골 노출 여부) 결정이 남아있는지 체크한다."
    ],
    "do_not_invent": [
      "고객명, 예산, 보안 사고, 운영 장애, 법무 승인, 추가 리스크·마감일, 추가 Owner 등은 본 회의록에 언급되지 않았으므로 추론·추가 기입 금지.",
      "개인적 판단으로 책임자/기한을 임의 부여하지 않는다.",
      "회의에서 거절된 제안(예: packageName mismatch 무시 처리)은 승인된 조치로 바꾸지 않는다."
    ]
  },
  "non_invention_rules": [
    "모든 내용은 제공된 공개 안전 합성 회의 자료(PUBLIC_MEETING_SMOKE)에서만 추출한다.",
    "명시된 사실만 확정 항목으로 기록하고, 불확정·미확정 항목은 별도 분리한다.",
    "주어진 시간표(수요일 스트레치 골, 금요일 기준 action) 외의 절대 날짜, 추가 일정, 책임자, 예산, 고객, 보안/장애/법무 관련 사실은 생성하지 않는다.",
    "open questions는 결정/확정으로 바꾸지 않는다."
  ]
}
